113→/// Convert handler (exit_code, output) to MCP CallToolResult.
114→fn jjrm_result(result: (i32, String)) -> Result<CallToolResult, McpError> {
115→    let (code, output) = result;
116→    if code == 0 {
117→        Ok(CallToolResult::success(vec![Content::text(output)]))
118→    } else {
119→        Ok(CallToolResult::error(vec![Content::text(output)]))
120→    }
121→}
122→
123→
124→/// Return deserialization error as MCP error result.
125→fn jjrm_deser_error(cmd: &str, e: serde_json::Error) -> Result<CallToolResult, McpError> {
126→    Ok(CallToolResult::error(vec![Content::text(format!("jjx {}: invalid params: {}", cmd, e))]))
127→}
