 98→
 99→/// Validate RELDIR against Layer 1 safety constraints.
100→///
101→/// - Must not be empty
102→/// - Must not start with `/` (must be relative to home)
103→/// - Must not start with `.` (no relative traversal)
104→/// - Must contain at least one `/` (forces subdirectory depth)
105→pub fn jjrlg_validate_reldir(reldir: &str) -> Result<(), String> {
106→    if reldir.is_empty() {
107→        return Err("RELDIR must not be empty".to_string());
108→    }
109→    if reldir.starts_with('/') {
110→        return Err("RELDIR must not start with '/' (must be relative to home)".to_string());
111→    }
112→    if reldir.starts_with('.') {
113→        return Err("RELDIR must not start with '.' (no relative traversal)".to_string());
114→    }
115→    if !reldir.contains('/') {
116→        return Err("RELDIR must contain at least one '/' (forces subdirectory depth)".to_string());
117→    }
118→    Ok(())
119→}
120→
121→/// Validate a git ref (commit SHA, branch, tag) contains only safe characters.
122→fn zjjrlg_validate_git_ref(s: &str) -> Result<(), String> {
123→    if s.is_empty() {
124→        return Err("git ref must not be empty".to_string());
125→    }
126→    if s.chars().all(|c| c.is_ascii_alphanumeric() || matches!(c, '/' | '-' | '_' | '.')) {
127→        Ok(())
128→    } else {
129→        Err(format!("git ref contains invalid characters: '{}'", s))
130→    }
131→}
