268→/// Bind a legatio: validate RELDIR, SSH probe the fundus, cache regime
269→/// paths, mint and persist legatio token.
270→pub fn jjrlg_run_bind(args: jjrlg_BindArgs, officium_id: &str) -> (i32, String) {
271→    let cn = JJRLG_CMD_NAME_BIND;
272→    let mut output = vvco_Output::buffer();
273→
274→    // Layer 1: Rust constant validation
275→    if let Err(e) = jjrlg_validate_reldir(&args.reldir) {
276→        vvco_err!(output, "{}: RELDIR validation failed (Layer 1): {}", cn, e);
277→        return (1, output.vvco_finish());
278→    }
279→
280→    let officium_dir = zjjrlg_officium_dir(officium_id);
281→    if !officium_dir.is_dir() {
282→        vvco_err!(output, "{}: officium directory not found", cn);
283→        return (1, output.vvco_finish());
284→    }
285→
286→    // Layer 3: SSH probe with resolved-path safety check
287→    //
288→    // Validates on the fundus that:
289→    // 1. RELDIR resolves to a real directory
290→    // 2. Resolved path is strictly under $HOME
291→    // 3. Resolved path has at least 2 components under $HOME
292→    let probe_script = format!(
293→        concat!(
294→            "z_resolved=\"$(cd \"$HOME/{reldir}\" 2>/dev/null && pwd)\" || exit 99\n",
295→            "case \"$z_resolved\" in\n",
296→            "  \"$HOME\"/*) ;;\n",
297→            "  *) echo \"FATAL: resolved dir not under HOME\"; exit 99 ;;\n",
298→            "esac\n",
299→            "z_depth=\"${{z_resolved#\"$HOME\"/}}\"\n",
300→            "case \"$z_depth\" in\n",
301→            "  */*) ;;\n",
302→            "  *) echo \"FATAL: resolved dir too shallow under HOME\"; exit 99 ;;\n",
303→            "esac\n",
304→            "echo \"PROBE_OK:$z_resolved\""
305→        ),
306→        reldir = args.reldir
307→    );
308→
309→    vvco_out!(output, "Probing {}@{}:~/{} ...", args.user, args.host, args.reldir);
310→
311→    let probe_result = match zjjrlg_ssh_exec(&args.host, &args.user, &probe_script) {
312→        Ok(r) => r,
313→        Err(e) => {
314→            vvco_err!(output, "{}: SSH probe failed: {}", cn, e);
315→            return (1, output.vvco_finish());
316→        }
317→    };
318→
319→    if probe_result.exit_code != 0 {
320→        let stderr = String::from_utf8_lossy(&probe_result.stderr);
321→        let stdout = String::from_utf8_lossy(&probe_result.stdout);
322→        vvco_err!(output, "{}: SSH probe failed (exit {})", cn, probe_result.exit_code);
323→        if !stdout.trim().is_empty() { vvco_err!(output, "  stdout: {}", stdout.trim()); }
324→        if !stderr.trim().is_empty() { vvco_err!(output, "  stderr: {}", stderr.trim()); }
325→        return (1, output.vvco_finish());
326→    }
327→
328→    let stdout = String::from_utf8_lossy(&probe_result.stdout);
329→    if !stdout.contains("PROBE_OK:") {
330→        vvco_err!(output, "{}: probe did not return PROBE_OK sentinel", cn);
331→        return (1, output.vvco_finish());
332→    }
333→
334→    vvco_out!(output, "RELDIR probe passed.");
335→
336→    // Read BURC_OUTPUT_ROOT_DIR from fundus .buk/burc.env
337→    let burc_cmd = format!(
338→        "cd \"$HOME/{}\" && cat .buk/burc.env 2>/dev/null | grep '^BURC_OUTPUT_ROOT_DIR=' | head -1",
339→        args.reldir
340→    );
341→
342→    let burc_result = match zjjrlg_ssh_exec(&args.host, &args.user, &burc_cmd) {
343→        Ok(r) => r,
344→        Err(e) => {
345→            vvco_err!(output, "{}: failed to read burc.env: {}", cn, e);
346→            return (1, output.vvco_finish());
347→        }
348→    };
349→
350→    let burc_stdout = String::from_utf8_lossy(&burc_result.stdout);
351→    let output_root_dir = burc_stdout.trim()
352→        .strip_prefix("BURC_OUTPUT_ROOT_DIR=")
353→        .unwrap_or("")
354→        .trim_matches('"')
355→        .trim_matches('\'')
356→        .to_string();
357→
358→    if output_root_dir.is_empty() {
359→        vvco_err!(output, "{}: BURC_OUTPUT_ROOT_DIR not found in fundus .buk/burc.env", cn);
360→        return (1, output.vvco_finish());
361→    }
362→
363→    vvco_out!(output, "Fundus output root: {}", output_root_dir);
364→
365→    // Mint legatio token and persist state
366→    let token = zjjrlg_mint_token(&officium_dir);
367→    let state = jjrlg_LegatioState {
368→        host: args.host.clone(),
369→        user: args.user.clone(),
370→        reldir: args.reldir.clone(),
371→        output_root_dir: output_root_dir.clone(),
372→    };
373→
374→    if let Err(e) = zjjrlg_save_legatio(&officium_dir, &token, &state) {
375→        vvco_err!(output, "{}: {}", cn, e);
376→        return (1, output.vvco_finish());
377→    }
378→
379→    vvco_out!(output, "Legatio {} bound to {}@{}:~/{}", token, state.user, state.host, state.reldir);
380→    vvco_out!(output, "Output root: {}", output_root_dir);
381→
382→    (0, output.vvco_finish())
383→}
