666→// jjx_relay — async dispatch via nohup on fundus
667→// ============================================================================
668→

669→pub struct jjrlg_RelayArgs {
670→    pub legatio: String,
671→    pub tabtarget: String,
672→    pub timeout: u64,
673→    pub firemark: String,
674→}
675→
676→/// Launch an async dispatch on the fundus via nohup.
677→///
678→/// Mints a pensum token, launches the tabtarget via nohup wrapper over SSH,
679→/// reads initial burx.env to capture BURX_TEMP_DIR, persists pensum state.
680→pub fn jjrlg_run_relay(args: jjrlg_RelayArgs, officium_id: &str) -> (i32, String) {
681→    let cn = JJRLG_CMD_NAME_RELAY;
682→    let mut output = vvco_Output::buffer();
683→
684→    if let Err(e) = zjjrlg_validate_tabtarget(&args.tabtarget) {
685→        vvco_err!(output, "{}: {}", cn, e);
686→        return (1, output.vvco_finish());
687→    }
688→
689→    let officium_dir = zjjrlg_officium_dir(officium_id);
690→    if !officium_dir.is_dir() {
691→        vvco_err!(output, "{}: officium directory not found", cn);
692→        return (1, output.vvco_finish());
693→    }
694→
695→    // Load legatio state
696→    let state = match zjjrlg_load_legatio(&officium_dir, &args.legatio) {
697→        Ok(s) => s,
698→        Err(e) => {
699→            vvco_err!(output, "{}: {}", cn, e);
700→            return (1, output.vvco_finish());
701→        }
702→    };
703→
704→    // Mint pensum: lock → load → mint → persist → release
705→    let pensum = match zjjrlg_mint_pensum_locked(&args.firemark) {
706→        Ok(p) => p,
707→        Err(e) => {
708→            vvco_err!(output, "{}: {}", cn, e);
709→            return (1, output.vvco_finish());
710→        }
711→    };
712→    let pensum_token = pensum.jjrf_as_str().to_string();
713→    let pensum_display = pensum.jjrf_display();
714→
715→    vvco_out!(output, "Relaying {} via {} ({})", args.tabtarget, args.legatio, pensum_display);
716→
717→    // SSH #1: Launch nohup wrapper on fundus
718→    let nohup_script = zjjrlg_build_nohup_script(
719→        &state.reldir, &pensum_token, args.timeout, &args.tabtarget,
720→    );
721→
722→    let launch = match zjjrlg_ssh_exec(&state.host, &state.user, &nohup_script) {
723→        Ok(r) => r,
724→        Err(e) => {
725→            vvco_err!(output, "{}: SSH launch failed: {}", cn, e);
726→            return (1, output.vvco_finish());
727→        }
728→    };
729→
730→    let launch_stdout = String::from_utf8_lossy(&launch.stdout);
731→    if launch.exit_code != 0 || !launch_stdout.contains("RELAY_OK") {
732→        let stderr = String::from_utf8_lossy(&launch.stderr);
733→        vvco_err!(output, "{}: nohup launch failed (exit {})", cn, launch.exit_code);
734→        if !stderr.trim().is_empty() { vvco_err!(output, "  {}", stderr.trim()); }
735→        return (1, output.vvco_finish());
736→    }
737→
738→    vvco_out!(output, "Dispatch launched on fundus.");
739→
740→    // SSH #2: Read initial burx.env — poll with label matching to avoid stale reads
741→    let burx_script = format!("\
742→cd \"$HOME/{}\" || exit 1
743→z_retries=0
744→while [ $z_retries -lt {} ]; do
745→  if [ -f '{}/current/burx.env' ]; then
746→    z_label=$(grep '^BURX_LABEL=' '{}/current/burx.env' 2>/dev/null | head -1 | cut -d= -f2)
747→    if [ \"$z_label\" = '{}' ]; then
748→      cat '{}/current/burx.env'
749→      exit 0
750→    fi
751→  fi
752→  sleep {}
753→  z_retries=$((z_retries + 1))
754→done
755→exit 1",
756→        state.reldir,
757→        BURX_INITIAL_POLL_MAX_RETRIES,
758→        state.output_root_dir, state.output_root_dir, pensum_token,
759→        state.output_root_dir,
760→        BURX_INITIAL_POLL_DELAY_SECS,
761→    );
762→
763→    let burx = match zjjrlg_ssh_exec(&state.host, &state.user, &burx_script) {
764→        Ok(r) => r,
765→        Err(e) => {
766→            vvco_err!(output, "{}: SSH burx read failed: {}", cn, e);
767→            return (1, output.vvco_finish());
768→        }
769→    };
770→
771→    if burx.exit_code != 0 {
772→        vvco_err!(output, "{}: burx.env with matching label not found after {} retries",
773→            cn, BURX_INITIAL_POLL_MAX_RETRIES);
774→        return (1, output.vvco_finish());
775→    }
776→
777→    let burx_content = String::from_utf8_lossy(&burx.stdout);
778→    let burx_fields = zjjrlg_parse_burx(&burx_content);
779→
780→    let temp_dir = match burx_fields.get("BURX_TEMP_DIR") {
781→        Some(d) if !d.is_empty() => d.clone(),
782→        _ => {
783→            vvco_err!(output, "{}: BURX_TEMP_DIR not found in burx.env", cn);
784→            return (1, output.vvco_finish());
785→        }
786→    };
787→
788→    let pid = match burx_fields.get("BURX_PID") {
789→        Some(p) if !p.is_empty() => p.clone(),
790→        _ => {
791→            vvco_err!(output, "{}: BURX_PID not found in burx.env", cn);
792→            return (1, output.vvco_finish());
793→        }
794→    };
795→
796→    let began_at = burx_fields.get("BURX_BEGAN_AT").cloned().unwrap_or_default();
797→
798→    // Persist pensum state
799→    let pensum_state = jjrlg_PensumState {
800→        legatio: args.legatio.clone(),
801→        firemark: args.firemark.clone(),
802→        temp_dir: temp_dir.clone(),
803→        pid,
804→        tabtarget: args.tabtarget.clone(),
805→        timeout: args.timeout,
806→        began_at,
807→    };
808→
809→    if let Err(e) = zjjrlg_save_pensum(&officium_dir, &pensum_token, &pensum_state) {
810→        vvco_err!(output, "{}: {}", cn, e);
811→        return (1, output.vvco_finish());
812→    }
813→
814→    vvco_out!(output, "Pensum {} active.", pensum_display);
815→    vvco_out!(output, "Remote temp dir: {}", temp_dir);
816→
817→    (0, output.vvco_finish())
818→}
