820→// ============================================================================
821→// Pensum probe (shared by jjx_check)
822→// ============================================================================
823→
824→/// Result of a single pensum probe via SSH.
825→struct zjjrlg_ProbeResult {
826→    report: String,
827→    burx_fields: HashMap<String, String>,
828→    files: Vec<String>,
829→}
830→
831→/// Execute a single probe of a pensum's status via SSH.
832→///
833→/// Reads burx.env from the pensum's durable temp dir, checks for
834→/// BURX_EXIT_STATUS (terminal), probes PID via kill -0, and lists
835→/// files on terminal status.
836→fn zjjrlg_probe_pensum(
837→    legatio_state: &jjrlg_LegatioState,
838→    pensum_state: &jjrlg_PensumState,
839→) -> Result<zjjrlg_ProbeResult, String> {
840→    let probe_script = format!("\
841→if [ ! -f '{temp_dir}/burx.env' ]; then
842→  echo 'JJRLG_REPORT:lost'
843→  exit 0
844→fi
845→cat '{temp_dir}/burx.env'
846→echo 'JJRLG_BURX_END'
847→z_es=$(grep '^BURX_EXIT_STATUS=' '{temp_dir}/burx.env' 2>/dev/null | head -1 | cut -d= -f2)
848→if [ -n \"$z_es\" ]; then
849→  echo 'JJRLG_REPORT:stopped'
850→  echo 'JJRLG_FILES_BEGIN'
851→  ls -1 '{temp_dir}/'
852→  echo 'JJRLG_FILES_END'
853→else
854→  if kill -0 {pid} 2>/dev/null; then
855→    echo 'JJRLG_REPORT:running'
856→  else
857→    echo 'JJRLG_REPORT:orphaned'
858→  fi
859→fi",
860→        temp_dir = pensum_state.temp_dir,
861→        pid = pensum_state.pid,
862→    );
863→
864→    let result = zjjrlg_ssh_exec(
865→        &legatio_state.host,
866→        &legatio_state.user,
867→        &probe_script,
868→    ).map_err(|e| format!("SSH probe failed: {}", e))?;
869→
870→    let stdout = String::from_utf8_lossy(&result.stdout);
871→
872→    // Parse report line
873→    let report = stdout.lines()
874→        .find(|l| l.starts_with("JJRLG_REPORT:"))
875→        .map(|l| l["JJRLG_REPORT:".len()..].to_string())
876→        .unwrap_or_else(|| "unknown".to_string());
877→
878→    // Parse BURX fields (lines before JJRLG_BURX_END, excluding sentinel lines)
879→    let burx_content: String = stdout.lines()
880→        .take_while(|l| !l.starts_with("JJRLG_BURX_END"))
881→        .filter(|l| !l.starts_with("JJRLG_"))
882→        .collect::<Vec<_>>()
883→        .join("\n");
884→    let burx_fields = zjjrlg_parse_burx(&burx_content);
885→
886→    // Parse file list (between JJRLG_FILES_BEGIN and JJRLG_FILES_END)
887→    let mut in_files = false;
888→    let mut files = Vec::new();
889→    for line in stdout.lines() {
890→        if line == "JJRLG_FILES_BEGIN" {
891→            in_files = true;
892→            continue;
893→        }
894→        if line == "JJRLG_FILES_END" {
895→            break;
896→        }
897→        if in_files && !line.is_empty() {
898→            files.push(line.to_string());
899→        }
900→    }
901→
902→    Ok(zjjrlg_ProbeResult { report, burx_fields, files })
903→}
904→
905→/// Format probe result into output buffer.
906→fn zjjrlg_format_probe_output(pensum_display: &str, probe: &zjjrlg_ProbeResult, output: &mut vvco_Output) {
907→    vvco_out!(output, "Pensum: {}", pensum_display);
908→    vvco_out!(output, "Report: {}", probe.report);
909→
910→    for key in &["BURX_PID", "BURX_BEGAN_AT", "BURX_TABTARGET", "BURX_TEMP_DIR",
911→                  "BURX_TRANSCRIPT", "BURX_LOG_HIST", "BURX_LABEL",
912→                  "BURX_EXIT_STATUS", "BURX_ENDED_AT"] {
913→        if let Some(val) = probe.burx_fields.get(*key) {
