 932→pub struct jjrlg_CheckArgs {
 933→    pub pensum: String,
 934→    pub timeout: u64,
 935→}
 936→
 937→/// Probe or poll a pensum's status on the fundus.
 938→///
 939→/// timeout=0: instant probe (single SSH round-trip).
 940→/// timeout>0: poll until terminal state or timeout expires.
 941→///
 942→/// Returns BURX fields + liveness report (running/orphaned/stopped/lost).
 943→/// On terminal status (stopped), also returns file list from BURX_TEMP_DIR.
 944→pub fn jjrlg_run_check(args: jjrlg_CheckArgs, officium_id: &str) -> (i32, String) {
 945→    let cn = JJRLG_CMD_NAME_CHECK;
 946→    let mut output = vvco_Output::buffer();
 947→
 948→    let officium_dir = zjjrlg_officium_dir(officium_id);
 949→
 950→    let parsed = match crate::jjrf_favor::jjrf_Pensum::jjrf_parse(&args.pensum) {
 951→        Ok(p) => p,
 952→        Err(e) => {
 953→            vvco_err!(output, "{}: invalid pensum: {}", cn, e);
 954→            return (1, output.vvco_finish());
 955→        }
 956→    };
 957→    let pensum_token = parsed.jjrf_as_str().to_string();
 958→    let pensum_display = parsed.jjrf_display();
 959→
 960→    let pensum_state = match zjjrlg_load_pensum(&officium_dir, &pensum_token) {
 961→        Ok(s) => s,
 962→        Err(e) => {
 963→            vvco_err!(output, "{}: {}", cn, e);
 964→            return (1, output.vvco_finish());
 965→        }
 966→    };
 967→
 968→    let legatio_state = match zjjrlg_load_legatio(&officium_dir, &pensum_state.legatio) {
 969→        Ok(s) => s,
 970→        Err(e) => {
 971→            vvco_err!(output, "{}: {}", cn, e);
 972→            return (1, output.vvco_finish());
 973→        }
 974→    };
 975→
 976→    let deadline = if args.timeout > 0 {
 977→        Some(std::time::Instant::now() + std::time::Duration::from_secs(args.timeout))
 978→    } else {
 979→        None
 980→    };
 981→
 982→    loop {
 983→        let probe = match zjjrlg_probe_pensum(&legatio_state, &pensum_state) {
 984→            Ok(p) => p,
 985→            Err(e) => {
 986→                vvco_err!(output, "{}: {}", cn, e);
 987→                return (1, output.vvco_finish());
 988→            }
 989→        };
 990→
 991→        let is_terminal = probe.report == "stopped" || probe.report == "lost";
 992→
 993→        if is_terminal || deadline.is_none() {
 994→            zjjrlg_format_probe_output(&pensum_display, &probe, &mut output);
 995→            return (0, output.vvco_finish());
 996→        }
 997→
 998→        if let Some(dl) = deadline {
 999→            if std::time::Instant::now() >= dl {
1000→                zjjrlg_format_probe_output(&pensum_display, &probe, &mut output);
1001→                return (0, output.vvco_finish());
1002→            }
1003→        }
1004→
1005→        std::thread::sleep(std::time::Duration::from_secs(BURX_CHECK_POLL_INTERVAL_SECS));
1006→    }
1007→}
