  5→//! Favor encoding - Firemark, Coronet, and Pensum identity types
  6→//!
  7→//! Implements base64url encoding/decoding for Job Jockey identity types:
  8→//! - Firemark: Heat identity (2 base64url chars, 0-4095)
  9→//! - Coronet: Pace identity (5 base64url chars, globally unique)
 10→//! - Pensum: Remote dispatch identity (5 chars with % sentinel, globally unique)
 11→
 12→use serde::{Deserialize, Serialize};
 13→
 14→/// URL-safe base64 charset (RFC 4648 section 5)
 15→pub const JJRF_CHARSET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
 16→
 17→/// Encoding radix — derived from charset length
 18→pub const JJRF_RADIX: u32 = JJRF_CHARSET.len() as u32;
 19→
 20→/// Firemark prefix character
 21→pub const JJRF_FIREMARK_PREFIX: char = '₣';
 22→
 23→/// Coronet prefix character
 24→pub const JJRF_CORONET_PREFIX: char = '₢';
 25→
 26→/// Pensum prefix character
 27→pub const JJRF_PENSUM_PREFIX: char = '₱';
 28→
 29→/// Pensum sentinel character — literal `%` at position 3 disambiguates from Coronet
 30→pub const JJRF_PENSUM_SENTINEL: char = '%';
 31→
 32→/// Maximum value for Firemark (RADIX^2 - 1)
 33→pub const JJRF_FIREMARK_MAX: u16 = (JJRF_RADIX * JJRF_RADIX - 1) as u16;
 34→
 35→/// Maximum value for Coronet pace index (RADIX^3 - 1)
 36→pub const JJRF_CORONET_PACE_MAX: u32 = JJRF_RADIX * JJRF_RADIX * JJRF_RADIX - 1;
 37→
 38→/// Maximum value for Pensum index (RADIX^2 - 1)
 39→pub const JJRF_PENSUM_INDEX_MAX: u32 = JJRF_RADIX * JJRF_RADIX - 1;
 40→
 41→/// Look up the position of a character in the charset
 42→pub fn zjjrf_char_to_value(c: char) -> Result<u8, String> {
 43→    let byte = c as u8;
 44→    JJRF_CHARSET
 45→        .iter()
 46→        .position(|&b| b == byte)
 47→        .map(|pos| pos as u8)
 48→        .ok_or_else(|| format!("Invalid base64 character: '{}'", c))
 49→}
 50→
 51→/// Get the character at a given position in the charset
 52→pub fn zjjrf_value_to_char(value: u8) -> char {
 53→    JJRF_CHARSET[value as usize] as char
 54→}
 55→
 56→/// Heat identity - 2 base64 characters encoding 0-4095
 57→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 58→pub struct jjrf_Firemark(pub String);
 59→
 60→/// Pace identity - 5 base64 characters, globally unique
 61→/// First 2 chars encode parent Heat, last 3 encode pace index (0-262143)
 62→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 63→pub struct jjrf_Coronet(pub String);
 64→
 65→/// Pensum identity - 5 characters, globally unique
 66→/// Format: 2 base64url (heat firemark) + literal `%` + 2 base64url (index within heat)
 67→/// Example: `Ah%BE` belongs to heat `₣Ah`
 68→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 69→pub struct jjrf_Pensum(pub String);
 70→
 71→impl jjrf_Firemark {
 72→    /// Encode an integer (0-4095) as a Firemark
 73→    pub fn jjrf_encode(value: u16) -> Self {
 74→        debug_assert!(value <= JJRF_FIREMARK_MAX, "Firemark value {} exceeds max {}", value, JJRF_FIREMARK_MAX);
 75→        let radix = JJRF_RADIX as u16;
 76→        let high = zjjrf_value_to_char((value / radix) as u8);
 77→        let low = zjjrf_value_to_char((value % radix) as u8);
 78→        jjrf_Firemark(format!("{}{}", high, low))
 79→    }
 80→
 81→    /// Decode a Firemark to its integer value
 82→    pub fn jjrf_decode(&self) -> Result<u16, String> {
 83→        let chars: Vec<char> = self.0.chars().collect();
 84→        if chars.len() != 2 {
 85→            return Err(format!("Firemark must be 2 characters, got {}", chars.len()));
 86→        }
 87→        let high = zjjrf_char_to_value(chars[0])? as u16;
 88→        let low = zjjrf_char_to_value(chars[1])? as u16;
 89→        Ok(high * JJRF_RADIX as u16 + low)
 90→    }
 91→
 92→    /// Parse a Firemark from string input (with or without prefix)
 93→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
 94→        let stripped = input.strip_prefix(JJRF_FIREMARK_PREFIX).unwrap_or(input);
 95→        if stripped.len() != 2 {
 96→            return Err(format!(
 97→                "Firemark must be 2 base64 characters (with or without {} prefix), got '{}'",
 98→                JJRF_FIREMARK_PREFIX, input
 99→            ));
100→        }
101→        // Validate all characters are in charset
102→        for c in stripped.chars() {
103→            zjjrf_char_to_value(c)?;
104→        }
105→        Ok(jjrf_Firemark(stripped.to_string()))
106→    }
107→
108→    /// Get the raw base64 string (without prefix)
109→    pub fn jjrf_as_str(&self) -> &str {
110→        &self.0
111→    }
112→
113→    /// Format with prefix for display
114→    pub fn jjrf_display(&self) -> String {
115→        format!("{}{}", JJRF_FIREMARK_PREFIX, self.0)
116→    }
117→}
