119→impl jjrf_Coronet {
120→    /// Encode a Heat identity and pace index as a Coronet
121→    pub fn jjrf_encode(heat: &jjrf_Firemark, pace_index: u32) -> Self {
122→        debug_assert!(
123→            pace_index <= JJRF_CORONET_PACE_MAX,
124→            "Coronet pace index {} exceeds max {}",
125→            pace_index,
126→            JJRF_CORONET_PACE_MAX
127→        );
128→        let p2 = zjjrf_value_to_char((pace_index / (JJRF_RADIX * JJRF_RADIX)) as u8);
129→        let p1 = zjjrf_value_to_char(((pace_index / JJRF_RADIX) % JJRF_RADIX) as u8);
130→        let p0 = zjjrf_value_to_char((pace_index % JJRF_RADIX) as u8);
131→        jjrf_Coronet(format!("{}{}{}{}", heat.jjrf_as_str(), p2, p1, p0))
132→    }
133→
134→    /// Decode a Coronet to its parent Heat and pace index
135→    pub fn jjrf_decode(&self) -> Result<(jjrf_Firemark, u32), String> {
136→        let chars: Vec<char> = self.0.chars().collect();
137→        if chars.len() != 5 {
138→            return Err(format!("Coronet must be 5 characters, got {}", chars.len()));
139→        }
140→        let heat = jjrf_Firemark(chars[0..2].iter().collect());
141→        let p2 = zjjrf_char_to_value(chars[2])? as u32;
142→        let p1 = zjjrf_char_to_value(chars[3])? as u32;
143→        let p0 = zjjrf_char_to_value(chars[4])? as u32;
144→        let pace_index = p2 * JJRF_RADIX * JJRF_RADIX + p1 * JJRF_RADIX + p0;
145→        Ok((heat, pace_index))
146→    }
147→
148→    /// Parse a Coronet from string input (with or without prefix)
149→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
150→        let stripped = input.strip_prefix(JJRF_CORONET_PREFIX).unwrap_or(input);
151→        if stripped.len() != 5 {
152→            return Err(format!(
153→                "Coronet must be 5 base64 characters (with or without {} prefix), got '{}'",
154→                JJRF_CORONET_PREFIX, input
155→            ));
156→        }
157→        // Validate all characters are in charset
158→        for c in stripped.chars() {
159→            zjjrf_char_to_value(c)?;
160→        }
161→        Ok(jjrf_Coronet(stripped.to_string()))
162→    }
