164→    /// Get the raw base64 string (without prefix)
165→    pub fn jjrf_as_str(&self) -> &str {
166→        &self.0
167→    }
168→
169→    /// Format with prefix for display
170→    pub fn jjrf_display(&self) -> String {
171→        format!("{}{}", JJRF_CORONET_PREFIX, self.0)
172→    }
