180→impl jjrf_Pensum {
181→    /// Encode a Heat firemark and index as a Pensum
182→    pub fn jjrf_encode(heat: &jjrf_Firemark, index: u32) -> Self {
183→        debug_assert!(
184→            index <= JJRF_PENSUM_INDEX_MAX,
185→            "Pensum index {} exceeds max {}",
186→            index,
187→            JJRF_PENSUM_INDEX_MAX
188→        );
189→        let high = zjjrf_value_to_char((index / JJRF_RADIX) as u8);
190→        let low = zjjrf_value_to_char((index % JJRF_RADIX) as u8);
191→        jjrf_Pensum(format!("{}{}{}{}",
192→            heat.jjrf_as_str(),
193→            JJRF_PENSUM_SENTINEL,
194→            high,
195→            low,
196→        ))
197→    }
198→
199→    /// Decode a Pensum to its parent Heat firemark and index
200→    pub fn jjrf_decode(&self) -> Result<(jjrf_Firemark, u32), String> {
201→        let chars: Vec<char> = self.0.chars().collect();
202→        if chars.len() != 5 {
203→            return Err(format!("Pensum must be 5 characters, got {}", chars.len()));
204→        }
205→        if chars[2] != JJRF_PENSUM_SENTINEL {
206→            return Err(format!(
207→                "Pensum must have '{}' sentinel at position 3, got '{}'",
208→                JJRF_PENSUM_SENTINEL, chars[2]
209→            ));
210→        }
211→        let heat = jjrf_Firemark(chars[0..2].iter().collect());
212→        let high = zjjrf_char_to_value(chars[3])? as u32;
213→        let low = zjjrf_char_to_value(chars[4])? as u32;
214→        Ok((heat, high * JJRF_RADIX + low))
215→    }
216→
217→    /// Parse a Pensum from string input (with or without prefix)
218→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
219→        let stripped = input.strip_prefix(JJRF_PENSUM_PREFIX).unwrap_or(input);
220→        if stripped.len() != 5 {
221→            return Err(format!(
222→                "Pensum must be 5 characters (with or without {} prefix), got '{}'",
223→                JJRF_PENSUM_PREFIX, input
224→            ));
225→        }
226→        let chars: Vec<char> = stripped.chars().collect();
227→        if chars[2] != JJRF_PENSUM_SENTINEL {
228→            return Err(format!(
229→                "Pensum must have '{}' sentinel at position 3, got '{}'",
230→                JJRF_PENSUM_SENTINEL, chars[2]
231→            ));
232→        }
233→        // Validate firemark chars (positions 0-1)
234→        zjjrf_char_to_value(chars[0])?;
235→        zjjrf_char_to_value(chars[1])?;
236→        // Validate index chars (positions 3-4)
237→        zjjrf_char_to_value(chars[3])?;
238→        zjjrf_char_to_value(chars[4])?;
239→        Ok(jjrf_Pensum(stripped.to_string()))
240→    }
241→
242→    /// Get the raw string (without prefix)
243→    pub fn jjrf_as_str(&self) -> &str {
244→        &self.0
245→    }
246→
247→    /// Format with prefix for display
248→    pub fn jjrf_display(&self) -> String {
249→        format!("{}{}", JJRF_PENSUM_PREFIX, self.0)
250→    }

